import * as React from 'react';
import { createComponent } from '../create-component.js';
import Component from '../../components/icon-button/src/icon-button.component.js';
const tagName = 'made-icon-button';
Component.define('made-icon-button');
/**
 * @summary Use icon buttons to display actions in a compact layout.
 * Icon buttons can represent opening actions such as opening an
 * overflow menu or search, or represent binary actions that can be
 * toggled on and off, such as favorite or bookmark.
 * @documentation '../../components/icon-button/stories/icon-button.mdx'
 *
 * @fires input {InputEvent} Dispatched when a toggle button toggles
 * @fires change {Event} Dispatched when a toggle button toggles
 *
 * @dependency made-icon
 *
 * @slot - The icon button's content.
 *
 * @csspart base - The component's base wrapper.
 * @csspart icon - The component's icon wrapper.
 * @csspart icon-selected - The component's icon wrapper when selected.
 */
const reactWrapper = createComponent({
    tagName,
    elementClass: Component,
    react: React,
    events: {},
    displayName: 'MadeIconButton'
});
export default reactWrapper;
